class Solution(object):
    def checkEqualPartitions(self, nums, target):
        n = len(nums)
        for mask in range(1, (1 << n) - 1):  # non-empty, not all
            prod_a = 1
            prod_b = 1
            for i in range(n):
                if mask >> i & 1:
                    prod_a *= nums[i]
                    if prod_a > target:
                        break
                else:
                    prod_b *= nums[i]
                    if prod_b > target:
                        break
            if prod_a == target and prod_b == target:
                return True
        return False
